import { listSkills, type SkillMeta } from "@/lib/skills";
import { listCliTools, type CliToolMeta } from "@/lib/cliTools";
import { ConnectorLogo } from "@/app/[lang]/connectors/Logo";
import { SkillLogo } from "@/app/[lang]/skills/Logo";
